from langflow.custom import Component
from langflow.io import DataInput, MessageTextInput, Output
from langflow.schema import Data
import json

class FilterCustomer(Component):
    display_name = "Filter Customer"
    inputs = [
        DataInput(name="file_data", display_name="File Data"),
        MessageTextInput(name="customer_id", display_name="Customer ID"),
    ]
    outputs = [Output(display_name="Customer", name="customer", method="filter")]

    def filter(self) -> Data:
        raw = self.file_data.data if hasattr(self.file_data, "data") else self.file_data
        if isinstance(raw, dict):
            raw = raw.get("text", raw.get("value", raw))
        if isinstance(raw, str):
            raw = json.loads(raw)
        match = next((c for c in raw if c["customer_id"] == self.customer_id), None)
        return Data(data=match or {})

