from langflow.custom import Component
from langflow.io import DataInput, Output
from langflow.schema.message import Message
import json

class CorpusToText(Component):
    display_name = "Corpus To Text"
    inputs = [DataInput(name="corpus", display_name="Corpus")]
    outputs = [Output(display_name="Text", name="text", method="to_text")]

    def to_text(self) -> Message:
        raw = getattr(self.corpus, "data", self.corpus)
        if isinstance(raw, dict):
            raw = raw.get("text", raw.get("value", raw))
        if isinstance(raw, str):
            raw = json.loads(raw)
        parts = []
        for doc in raw:
            for p in doc.get("passages", []):
                parts.append(p)
        return Message(text="\n\n".join(parts))

from langflow.custom import Component
from langflow.io import DataInput, Output
from langflow.schema.message import Message
import json

class CustomerSchema(Component):
    display_name = "Customer Schema"
    inputs = [DataInput(name="customer_file", display_name="Customer File")]
    outputs = [Output(display_name="Schema", name="schema", method="extract")]

    def extract(self) -> Message:
        raw = getattr(self.customer_file, "data", self.customer_file)
        if isinstance(raw, dict):
            raw = raw.get("text", raw.get("value", raw))
        if isinstance(raw, str):
            raw = json.loads(raw)
        sample = raw[0]

        lines = ["CUSTOMER FIELDS (use these exact names in conditions):"]
        for k, v in sample.items():
            if k == "holdings":
                continue
            lines.append(f"- {k} ({type(v).__name__})")
        lines.append("")
        lines.append("HOLDINGS is a list; each holding has:")
        if sample.get("holdings"):
            for k, v in sample["holdings"][0].items():
                lines.append(f"- holdings[].{k} ({type(v).__name__})")
        lines.append("")

        # discover categorical fields from the data itself: any field whose
        # values are strings or lists of strings (not numbers/bools/ids)
        lines.append("ALLOWED VALUES (use ONLY these exact values in conditions, never invent new ones):")
        skip = {"holdings", "customer_id", "edge_case", "edge_case_note"}
        for k in sample.keys():
            if k in skip:
                continue
            vals = set()
            is_categorical = False
            for rec in raw:
                v = rec.get(k)
                if isinstance(v, str):
                    vals.add(v); is_categorical = True
                elif isinstance(v, list) and v and all(isinstance(i, str) for i in v):
                    vals.update(v); is_categorical = True
            # only list fields with a small, repeating set of values (real categories,
            # not free text or unique ids)
            if is_categorical and 0 < len(vals) <= 30:
                lines.append(f"- {k}: {sorted(vals)}")
        lines.append("")
        lines.append("Use operator 'holds_product' / 'not_holds_product' to test holdings by product_id.")
        return Message(text="\n".join(lines))

from langflow.custom import Component
from langflow.io import DataInput, MessageInput, MessageTextInput, Output
from langflow.schema import Data
from langflow.schema.message import Message
import json
from datetime import datetime, timezone

ACTION_ORDER = ["Silent", "Contact path", "Inform", "Recommend"]
def rank(l):
    try: return ACTION_ORDER.index(l)
    except ValueError: return 0
def lower_of(a, b):
    return ACTION_ORDER[min(rank(a), rank(b))]

def check_condition(customer, cond):
    field = cond.get("field")
    op = cond.get("operator")
    val = cond.get("value")

    # holds / not_holds: test against the customer's holdings list
    if op in ("holds_product", "not_holds_product"):
        held = [h.get("product_id") for h in customer.get("holdings", [])]
        is_held = val in held
        return is_held if op == "holds_product" else not is_held

    actual = customer.get(field)
    if actual is None:
        return False

    try:
        if op == "equals":
            return actual == val
        if op == "not_equals":
            return actual != val
        if op == "greater_than":
            return actual > val
        if op == "less_than":
            return actual < val
        if op == "greater_than_or_equal":
            return actual >= val
        if op == "less_than_or_equal":
            return actual <= val
        if op == "between":
            return val[0] <= actual <= val[1]
        if op == "in":
            # rule value is a list of allowed options.
            # if the customer's field is itself a list (e.g. financial_goals),
            # pass when ANY of the customer's values is in the allowed options.
            if isinstance(actual, list):
                return any(a in val for a in actual)
            return actual in val
        if op == "not_in":
            if isinstance(actual, list):
                return all(a not in val for a in actual)
            return actual not in val
        if op == "contains":
            # customer field is a list; pass if it contains the rule value
            if isinstance(actual, list):
                return val in actual
            return val in str(actual)
    except TypeError:
        return False
    return False

class GateEngine(Component):
    display_name = "Gate Engine"
    inputs = [
        MessageInput(name="candidates", display_name="Brain Candidates (JSON)"),
        MessageInput(name="rulebook", display_name="Rulebook (JSON)"),
        DataInput(name="customer", display_name="Customer"),
        MessageTextInput(name="consent_mode", display_name="Consent Mode (1 or 2)", value="1"),
    ]
    outputs = [
        Output(display_name="Decision (data)", name="decision", method="decide"),
        Output(display_name="Readable", name="readable", method="readable"),
    ]

    def _parse(self, x):
        raw = getattr(x, "data", None)
        if raw is None:
            raw = getattr(x, "text", x)
        if isinstance(raw, dict):
            if "value" in raw: raw = raw["value"]
            elif "text" in raw: raw = raw["text"]
            else: return raw
        if not isinstance(raw, str):
            return raw
        s = raw.strip().strip("`").strip()
        if s.startswith("json"):
            s = s[4:].strip()
        start = next((i for i, ch in enumerate(s) if ch in "[{"), -1)
        if start == -1:
            return {}
        try:
            obj, _ = json.JSONDecoder().raw_decode(s[start:])
            return obj
        except json.JSONDecodeError:
            # last resort: clip to the last closing bracket and retry
            s2 = s[start:]
            end = max(s2.rfind("]"), s2.rfind("}"))
            if end != -1:
                return json.loads(s2[:end+1])
            raise

    def _evaluate(self, cand, rules, cust, mode):
        rec = cand.get("recommended_product_id")
        trig = cand.get("trigger_product_id")
        intended = cand.get("intended_action_level", "Recommend")
        held = [h.get("product_id") for h in cust.get("holdings", [])]
        gates = {}

        # GATE 1+2: match a rule on BOTH trigger and recommended, customer must hold trigger
        match = next((r for r in rules
                      if r.get("recommended_product_id") == rec
                      and r.get("trigger_product_id") == trig), None)
        if match is None:
            gates["rule_match"] = {"verdict": "blocked",
                "why": f"no approved rule offers {rec} to a holder of {trig}"}
            return "Silent", "rule_match", gates, None
        if trig not in held:
            gates["rule_match"] = {"verdict": "blocked",
                "why": f"customer does not hold the required trigger product {trig}"}
            return "Silent", "rule_trigger", gates, match.get("rule_id")
        failed = [c for c in match.get("conditions", []) if not check_condition(cust, c)]
        if failed:
            gates["rule_match"] = {"verdict": "blocked", "rule_id": match.get("rule_id"),
                "why": "customer fails conditions: " + ", ".join(
                    f"{c.get('field')} {c.get('operator')} {c.get('value')}" for c in failed)}
            return "Silent", "rule_conditions", gates, match.get("rule_id")

        rule_cap = match.get("max_action_level", "Recommend")
        gates["rule_match"] = {"verdict": "pass", "rule_id": match.get("rule_id"),
            "rule_cap": rule_cap}
        permitted = lower_of(intended, rule_cap)
        capped_by = "rulebook_cap" if rank(rule_cap) < rank(intended) else None

        # GATE 3: consent
        if str(mode).strip() == "1":
            gates["consent"] = {"verdict": "pass", "mode": "Mode 1 (group consent assumed)"}
        else:
            cv = cust.get("data_sharing_marketing_consent")
            ok = cv in ("explicit", "implicit")
            gates["consent"] = {"verdict": "pass" if ok else "blocked",
                "mode": "Mode 2 (per-customer)", "customer_consent": cv}
            if not ok:
                return "Silent", "consent", gates, match.get("rule_id")
        return permitted, capped_by, gates, match.get("rule_id")

    def _build(self):
        parsed = self._parse(self.candidates)
        cust = getattr(self.customer, "data", self.customer)
        rules = self._parse(self.rulebook)
        if isinstance(rules, dict): rules = rules.get("rules", [rules])
        cand_list = parsed.get("candidates", []) if isinstance(parsed, dict) else parsed
        mode = self.consent_mode

        evaluated = []
        winner = None
        for c in sorted(cand_list, key=lambda x: x.get("rank", 99)):
            permitted, capped_by, gates, rule_id = self._evaluate(c, rules, cust, mode)
            row = {
                "rank": c.get("rank"),
                "recommended_product_id": c.get("recommended_product_id"),
                "recommended_product_name": c.get("recommended_product_name"),
                "type": c.get("type"),
                "fit_bucket": c.get("fit_bucket"),
                "intended_action_level": c.get("intended_action_level"),
                "permitted_action_level": permitted,
                "capped_by": capped_by,
                "gate_verdicts": gates,
                "rulebook_rule": rule_id,
                "reason_code": c.get("reason_code"),
                "fit_reason": c.get("fit_reason"),
            }
            evaluated.append(row)
            if winner is None and permitted != "Silent":
                winner = row
        return {
            "customer_id": parsed.get("customer_id") if isinstance(parsed, dict) else cust.get("customer_id"),
            "consent_mode": str(mode).strip(),
            "winner": winner,
            "all_considered": evaluated,
            "timestamp": datetime.now(timezone.utc).isoformat(),
        }

    def decide(self) -> Data:
        return Data(data=self._build())

    def readable(self) -> Message:
        d = self._build()
        lines = [f"DECISION LOG — customer {d['customer_id']}  (consent {d['consent_mode']})", ""]
        w = d["winner"]
        if w:
            lines.append(f"RECOMMENDATION: {w['recommended_product_name']} ({w['recommended_product_id']})")
            lines.append(f"  action: {w['permitted_action_level']}  (brain wanted {w['intended_action_level']})")
            if w["capped_by"]:
                lines.append(f"  capped by: {w['capped_by']}")
            lines.append(f"  why fit: {w['fit_reason']}")
            lines.append(f"  reason code: {w['reason_code']}")
        else:
            lines.append("RECOMMENDATION: none — every candidate was blocked or silent.")
        lines.append("")
        lines.append("ALL CANDIDATES CONSIDERED:")
        for r in d["all_considered"]:
            mark = "WON" if (w and r["rank"] == w["rank"]) else "   "
            note = r["capped_by"] or (list(r["gate_verdicts"].get("rule_match", {}).values())[-1]
                                      if r["permitted_action_level"] == "Silent" else "passed")
            lines.append(f"  [{mark}] rank {r['rank']} {r['fit_bucket']:>6} fit | "
                         f"{r['recommended_product_name']} | {r['intended_action_level']} -> "
                         f"{r['permitted_action_level']} | {note}")
        return Message(text="\n".join(lines))
